import { describe, expect, it } from "vitest";
import { compile } from "./compile.js";
import { detectNamingDialect } from "./dialect.js";

/**
 * Whole-spec naming dialect inference. Each fixture is shaped like a real
 * backtested spec family: Twilio (Verb+Resource ids over `.json` paths), Slack
 * (`namespace.method` paths), Stripe/HubSpot (autogenerated ids embedding their
 * own path), Zoom (bare resource nouns).
 */

describe("detectNamingDialect", () => {
  it("classifies Twilio-shaped Verb+Resource operationIds as verb_first (pascal)", () => {
    const report = detectNamingDialect([
      {
        operationId: "CreateMessage",
        path: "/2010-04-01/Accounts/{Sid}/Messages.json",
        method: "post",
      },
      {
        operationId: "ListMessage",
        path: "/2010-04-01/Accounts/{Sid}/Messages.json",
        method: "get",
      },
      {
        operationId: "FetchMessage",
        path: "/2010-04-01/Accounts/{Sid}/Messages/{MessageSid}.json",
        method: "get",
      },
      {
        operationId: "DeleteMessage",
        path: "/2010-04-01/Accounts/{Sid}/Messages/{MessageSid}.json",
        method: "delete",
      },
      { operationId: "CreateCall", path: "/2010-04-01/Accounts/{Sid}/Calls.json", method: "post" },
      { operationId: "ListCall", path: "/2010-04-01/Accounts/{Sid}/Calls.json", method: "get" },
    ]);
    expect(report.dialect).toBe("verb_first");
    expect(report.casing).toBe("pascal");
    expect(report.confidence).toBeGreaterThanOrEqual(0.7);
    expect(report.sampled).toBe(6);
    expect(report.signals.some((s) => s.includes("action verb"))).toBe(true);
  });

  it("does not mistake Twilio's `.json` path extension for a namespace", () => {
    const report = detectNamingDialect([
      { operationId: "CreateMessage", path: "/Accounts/{Sid}/Messages.json", method: "post" },
      { operationId: "ListMessage", path: "/Accounts/{Sid}/Messages.json", method: "get" },
      { operationId: "CreateCall", path: "/Accounts/{Sid}/Calls.json", method: "post" },
      { operationId: "ListCall", path: "/Accounts/{Sid}/Calls.json", method: "get" },
      { operationId: "DeleteCall", path: "/Accounts/{Sid}/Calls/{CallSid}.json", method: "delete" },
    ]);
    expect(report.dialect).toBe("verb_first");
  });

  it("classifies Slack-shaped dotted paths as namespace_method", () => {
    const report = detectNamingDialect([
      { operationId: "chat_postMessage", path: "/chat.postMessage", method: "post" },
      { operationId: "chat_delete", path: "/chat.delete", method: "post" },
      { operationId: "conversations_list", path: "/conversations.list", method: "get" },
      { operationId: "conversations_history", path: "/conversations.history", method: "get" },
      { operationId: "users_info", path: "/users.info", method: "get" },
      { operationId: "users_list", path: "/users.list", method: "get" },
    ]);
    expect(report.dialect).toBe("namespace_method");
    expect(report.confidence).toBeGreaterThanOrEqual(0.7);
  });

  it("classifies dot-namespaced RPC operationIds as namespace_method", () => {
    const report = detectNamingDialect([
      { operationId: "admin.users.list", path: "/rpc", method: "post" },
      { operationId: "admin.users.invite", path: "/rpc", method: "post" },
      { operationId: "admin.conversations.archive", path: "/rpc", method: "post" },
      { operationId: "team.info.get", path: "/rpc", method: "post" },
      { operationId: "team.billing.info", path: "/rpc", method: "post" },
    ]);
    expect(report.dialect).toBe("namespace_method");
  });

  it("classifies Stripe-shaped path-embedding operationIds as path_derived", () => {
    const report = detectNamingDialect([
      { operationId: "GetCharges", path: "/v1/charges", method: "get" },
      { operationId: "PostCharges", path: "/v1/charges", method: "post" },
      { operationId: "GetChargesCharge", path: "/v1/charges/{charge}", method: "get" },
      {
        operationId: "PostChargesChargeCapture",
        path: "/v1/charges/{charge}/capture",
        method: "post",
      },
      { operationId: "GetRefunds", path: "/v1/refunds", method: "get" },
      { operationId: "PostRefunds", path: "/v1/refunds", method: "post" },
    ]);
    // Also verb-first-looking (Post/Get) — the more specific autogen signal wins.
    expect(report.dialect).toBe("path_derived");
    expect(report.confidence).toBeGreaterThanOrEqual(0.7);
  });

  it("classifies HubSpot-shaped path-embedding operationIds as path_derived", () => {
    const report = detectNamingDialect([
      {
        operationId: "get-/crm/v3/objects/0-3_getPage",
        path: "/crm/v3/objects/0-3",
        method: "get",
      },
      {
        operationId: "post-/crm/v3/objects/0-3_create",
        path: "/crm/v3/objects/0-3",
        method: "post",
      },
      {
        operationId: "get-/crm/v3/objects/0-3/{id}_getById",
        path: "/crm/v3/objects/0-3/{id}",
        method: "get",
      },
      {
        operationId: "patch-/crm/v3/objects/0-3/{id}_update",
        path: "/crm/v3/objects/0-3/{id}",
        method: "patch",
      },
      {
        operationId: "delete-/crm/v3/objects/0-3/{id}_archive",
        path: "/crm/v3/objects/0-3/{id}",
        method: "delete",
      },
    ]);
    expect(report.dialect).toBe("path_derived");
    // These ids mix hyphens, slashes, and camelCase — no coherent casing.
    expect(report.casing).toBe("mixed");
  });

  it("classifies Zoom-shaped bare-noun operationIds as resource_only", () => {
    const report = detectNamingDialect([
      { operationId: "meetings", path: "/users/{userId}/meetings", method: "get" },
      { operationId: "meeting", path: "/meetings/{meetingId}", method: "get" },
      { operationId: "meetingCreate", path: "/users/{userId}/meetings", method: "post" },
      { operationId: "users", path: "/users", method: "get" },
      { operationId: "user", path: "/users/{userId}", method: "get" },
      { operationId: "webinars", path: "/users/{userId}/webinars", method: "get" },
    ]);
    expect(report.dialect).toBe("resource_only");
    expect(report.casing).toBe("camel"); // "meetingCreate" is the only casing signal
  });

  it("returns mixed with confidence 0 for fewer than 5 operations (small fixtures untouched)", () => {
    const report = detectNamingDialect([
      { operationId: "getCustomer", path: "/customers/{id}", method: "get" },
      { operationId: "createRefund", path: "/payments/{id}/refunds", method: "post" },
      { operationId: "capturePayment", path: "/payments/{id}/capture", method: "post" },
    ]);
    expect(report.dialect).toBe("mixed");
    expect(report.confidence).toBe(0);
    expect(report.sampled).toBe(3);
  });

  it("returns mixed when no style reaches a majority", () => {
    const report = detectNamingDialect([
      { operationId: "createRefund", path: "/payments/{id}/refunds", method: "post" },
      { operationId: "listPayments", path: "/payments", method: "get" },
      { operationId: "meetings", path: "/meetings", method: "get" },
      { operationId: "webinars", path: "/webinars", method: "get" },
      { operationId: "chat_postMessage", path: "/chat.postMessage", method: "post" },
      { operationId: "users_info", path: "/users.info", method: "get" },
    ]);
    expect(report.dialect).toBe("mixed");
  });
});

describe("dialect inference wired into compile()", () => {
  const ok = `responses: { "200": { description: ok } }`;

  it("emits one naming_dialect diagnostic and penalizes path_derived ids by 0.15", async () => {
    const stripeish = `openapi: 3.0.0
info: { title: ledgerish, version: 1.0.0 }
paths:
  /v1/charges:
    get:
      operationId: GetCharges
      ${ok}
    post:
      operationId: PostCharges
      ${ok}
  /v1/charges/{charge}:
    get:
      operationId: GetChargesCharge
      ${ok}
  /v1/charges/{charge}/capture:
    post:
      operationId: PostChargesChargeCapture
      ${ok}
  /v1/refunds:
    get:
      operationId: GetRefunds
      ${ok}
    post:
      operationId: PostRefunds
      ${ok}
`;
    const air = await compile({ spec: stripeish, serviceId: "ledgerish" });
    const dialects = air.diagnostics.filter((d) => d.code === "naming_dialect");
    expect(dialects).toHaveLength(1);
    expect(dialects[0]?.message).toContain("path_derived");
    // A declared operationId starts at 0.9; the corpus-wide autogen finding
    // subtracts 0.15 — the direction the per-dialect bug fixes generalized.
    const op = air.operations.find((o) => o.canonicalName === "get_charges");
    const claim = op?.evidence.claims.find((c) => c.predicate === "name.quality");
    expect(claim?.confidence).toBeCloseTo(0.75, 5);
  });

  it("boosts a coherent verb_first corpus by 0.05, capped at 0.95", async () => {
    const verby = `openapi: 3.0.0
info: { title: crm, version: 1.0.0 }
paths:
  /customers:
    get:
      operationId: listCustomers
      ${ok}
    post:
      operationId: createCustomer
      ${ok}
  /customers/{id}:
    get:
      operationId: getCustomer
      ${ok}
    patch:
      operationId: updateCustomer
      ${ok}
    delete:
      operationId: deleteCustomer
      ${ok}
`;
    const air = await compile({ spec: verby, serviceId: "crm" });
    const dialect = air.diagnostics.find((d) => d.code === "naming_dialect");
    expect(dialect?.message).toContain("verb_first");
    const op = air.operations.find((o) => o.canonicalName === "get_customer");
    const claim = op?.evidence.claims.find((c) => c.predicate === "name.quality");
    expect(claim?.confidence).toBeCloseTo(0.95, 5);
  });

  it("applies no adjustment below the 5-operation sample floor", async () => {
    const tiny = `openapi: 3.0.0
info: { title: mini, version: 1.0.0 }
paths:
  /widgets:
    get:
      operationId: listWidgets
      ${ok}
    post:
      operationId: createWidget
      ${ok}
`;
    const air = await compile({ spec: tiny, serviceId: "mini" });
    const dialect = air.diagnostics.find((d) => d.code === "naming_dialect");
    expect(dialect?.message).toContain("mixed");
    const op = air.operations.find((o) => o.canonicalName === "list_widgets");
    const claim = op?.evidence.claims.find((c) => c.predicate === "name.quality");
    expect(claim?.confidence).toBeCloseTo(0.9, 5); // untouched
  });
});
